    static final class UploadSession implements Closeable {
        final String uploadId;
        final Path finalPath;
        final Path tempPath;
        final String contentType;
        final AtomicLong bytesReceived = new AtomicLong(0);

        private OutputStream out;
        private boolean opened;
        private boolean committed;

        UploadSession(String uploadId, Path finalPath, Path tempPath, String contentType) {
            this.uploadId = uploadId;
            this.finalPath = finalPath;
            this.tempPath = tempPath;
            this.contentType = contentType == null ? "" : contentType;
        }

        void open() throws IOException {
            if (opened) return;
            Files.createDirectories(tempPath.getParent());
            out = Files.newOutputStream(tempPath, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING, StandardOpenOption.WRITE);
            opened = true;
        }

        void write(ByteString data) throws IOException {
            if (!opened || out == null) throw new IOException("session not open");
            if (committed) throw new IOException("already committed");
            if (data == null || data.isEmpty()) return;
            data.writeTo(out);
            bytesReceived.addAndGet(data.size());
        }

        void commit() throws IOException {
            if (!opened) throw new IOException("session not open");
            if (committed) return;
            try {
                out.flush();
            } finally {
                out.close();
                out = null;
            }
            Files.createDirectories(finalPath.getParent());
            try {
                Files.move(tempPath, finalPath, StandardCopyOption.ATOMIC_MOVE, StandardCopyOption.REPLACE_EXISTING);
            } catch (AtomicMoveNotSupportedException e) {
                Files.move(tempPath, finalPath, StandardCopyOption.REPLACE_EXISTING);
            }
            committed = true;
        }

        void abortQuietly() {
            try {
                close();
            } catch (IOException ignored) {
            }
            try {
                Files.deleteIfExists(tempPath);
            } catch (IOException ignored) {
            }
        }

        @Override
        public void close() throws IOException {
            if (out != null) {
                try {
                    out.flush();
                } finally {
                    out.close();
                    out = null;
                }
            }
        }
    }

    static final class CancellationInterceptor implements ServerInterceptor {
        @Override
        public <ReqT, RespT> ServerCall.Listener<ReqT> interceptCall(
                ServerCall<ReqT, RespT> call,
                io.grpc.Metadata headers,
                ServerCallHandler<ReqT, RespT> next
        ) {
            ServerCall.Listener<ReqT> listener = next.startCall(call, headers);
            Context ctx = Context.current();
            return new ServerCall.Listener<>() {
                @Override
                public void onCancel() {
                    if (!ctx.isCancelled()) {
                        ctx.cancel(null);
                    }
                    listener.onCancel();
                }

                @Override
                public void onMessage(ReqT message) {
                    listener.onMessage(message);
                }

                @Override
                public void onHalfClose() {
                    listener.onHalfClose();
                }

                @Override
                public void onReady() {
                    listener.onReady();
                }

                @Override
                public void onComplete() {
                    listener.onComplete();
                }
            };
        }
    }

